from curl_cffi import requests
import json
import time
from datetime import datetime
import os


def get_sofascore_data(url):
    """Fetches JSON data using curl_cffi to bypass advanced TLS fingerprinting."""
    headers = {
        "Accept": "*/*",
        "Origin": "https://www.sofascore.com",
        "Referer": "https://www.sofascore.com/"
    }

    print(f"Fetching: {url}")
    response = requests.get(url, headers=headers, impersonate="chrome")

    if response.status_code == 200:
        return response.json()
    else:
        print(f"Failed! Status code: {response.status_code}")
        return None


def extract_player_ratings(lineup_data, match_id):
    """Parses the lineup JSON and extracts ratings for both teams."""
    ratings_list = []
    if not lineup_data:
        return ratings_list

    for team_side in ['home', 'away']:
        if team_side in lineup_data:
            players = lineup_data[team_side].get('players', [])
            for p in players:
                player_info = p.get('player', {})
                stats = p.get('statistics', {})
                rating = stats.get('rating')

                if rating:
                    ratings_list.append({
                        "match_id": match_id,
                        "team": team_side,
                        "player_name": player_info.get('name'),
                        "player_id": player_info.get('id'),
                        "rating": rating
                    })
    return ratings_list


def save_data_locally(data, filename):
    """Saves the Python dictionary to a local JSON file."""
    with open(filename, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=4, ensure_ascii=False)
    print(f"Saved: {filename}")


